;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] ! o.クイーンスパイダー.contracted

@wait time=500 cond='WAY != "n"'
@walk turn=n cond='WAY != "n"'
@wait time=500
[texton]
[リーダー f=05]「...!」[k]
Suddenly, I sensed a sharp killing intent. Something is there![k]
[textoff]
@eval exp='game.party.lastWalk = "goBackward"'
@monster pos=3 name=クイーンスパイダー
@callbattle bgm=boss gameover=true
@delevent
@changefloor x=6 y=3 pimg=human

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] party.lastIsMove && ! o.クイーンスパイダー.contracted

@eval exp='game.contractableMonster = o.クイーンスパイダー'
@call storage="battle.ks" target=*contract_monster
[if exp='o.クイーンスパイダー.contracted']
	@delevent
	@changefloor x=6 y=3 pimg=void
[endif]

[eventoff]
;-------------------------------------------------------------------------------
